/**
 * SMS Page
 * 
 * Enables sending SMS messages to individual recipients or bulk contacts via
 * CSV file upload. Calculates SMS units based on character count, supports
 * different message types (promotional/transactional), and handles contact
 * file parsing for bulk messaging.
 */

import React, { useState, useEffect } from 'react';
import { useTranslation } from 'react-i18next';
import { cleanNumberForBackend } from '@/shared/utils/format-utils.js';
import { useToast } from '@/app/providers/ToastContext.jsx';
import { useMutation } from '@/shared/hooks';
import { queryKeys } from '@/shared/utils/queryKeys.js';
import logger from '@/shared/utils/logger.js';
import { API_CONFIG } from '@/app/config/apiConfig.js';
import '/styles/pages/Dashboard.css';
import '/styles/components/ui.css';

function SMS() {
  const { t } = useTranslation();
  const { success, error: showError } = useToast();

  const [formData, setFormData] = useState({
    recipientNumber: '',
    recipientFile: null,
    uploadedContacts: [],
    textMessage: '',
    smsType: 'promotional',
    senderId: '',
    encoding: 'Default',
    audience: 'Quick Number List'
  });

  const [formErrors, setFormErrors] = useState({});
  const [smsStats, setSmsStats] = useState({
    characterCount: 0,
    smsUnits: 0
  });

  useEffect(() => {
    setSmsStats(calculateSmsUnits(formData.textMessage));
  }, [formData.textMessage]);

  const calculateSmsUnits = (text) => {
    const charCount = text.length;
    const units = Math.ceil(charCount / 160);
    return {
      characterCount: charCount,
      smsUnits: units
    };
  };

  const handleMessageChange = (e) => {
    const newText = e.target.value;
    setFormData((prev) => ({ ...prev, textMessage: newText }));
    setSmsStats(calculateSmsUnits(newText));
    // Clear error when user starts typing
    if (formErrors.textMessage) {
      setFormErrors(prev => ({ ...prev, textMessage: null }));
    }
  };

  const handleChange = (e) => {
    const { name, value, files } = e.target;
    if (name === 'recipientFile') {
      const file = files[0];
      setFormData((prev) => ({ ...prev, recipientFile: file }));
      if (file) {
        parseCSV(file);
      }
    } else {
      if (name === 'recipientNumber' && value) {
        const numbers = value.split(/[\s,;]+/).map(num => {
          if (num.trim().startsWith('0')) {
            return num.trim().substring(1);
          }
          return num.trim();
        }).filter(Boolean).join(',');
        setFormData((prev) => ({ ...prev, [name]: numbers }));
        // Clear error on input
        if (formErrors.recipientNumber) {
          setFormErrors(prev => ({ ...prev, recipientNumber: null }));
        }
      } else {
        setFormData((prev) => ({ ...prev, [name]: value }));
        // Clear error on input
        if (formErrors[name]) {
          setFormErrors(prev => ({ ...prev, [name]: null }));
        }
      }
    }
  };

  const parseCSV = (file) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      const csv = e.target.result;
      const lines = csv.split('\n');
      const contacts = [];
      for (let i = 1; i < lines.length; i++) { // Skip header row (i=0)
        const [name, number] = lines[i].split(',').map(item => item.trim());
        if (name && number) {
          // Clean number (remove plus and leading zero)
          let cleanedNumber = cleanNumberForBackend(number);
          // If not starting with country code, assume it's a local number
          if (!cleanedNumber.startsWith('233')) {
            cleanedNumber = '233' + cleanedNumber;
          }
          contacts.push({ name, number: cleanedNumber });
        }
      }
      setFormData((prev) => ({ ...prev, uploadedContacts: contacts }));
    };
    reader.readAsText(file);
  };

  const buildQueryString = (params) =>
    Object.keys(params)
      .filter((k) => params[k] !== undefined && params[k] !== null && params[k] !== '')
      .map((k) => `${encodeURIComponent(k)}=${encodeURIComponent(params[k])}`)
      .join('&');

  // Use React Query mutation for sending SMS
  const sendSMSMutation = useMutation({
    mutationFn: async (smsParams) => {
      // Extract phone numbers and send individual SMS for each
      const phoneNumbers = smsParams.phonenumber.split(',');
      const results = [];
      let successCount = 0;
      let failureCount = 0;
      const failedNumbers = [];

      for (const phoneNumber of phoneNumbers) {
        if (!phoneNumber.trim()) { continue; }

        try {
          const singleSmsParams = {
            ...smsParams,
            phonenumber: phoneNumber.trim() // Send one number at a time
          };
          const query = buildQueryString(singleSmsParams);
          const url = `${API_CONFIG.SMS_BASE_URL}?${query}`;
          const resp = await fetch(url, { method: 'GET', headers: { accept: 'application/json' } });

          if (!resp.ok) {
            const text = await resp.text();
            throw new Error(`SMS API Error: ${resp.status} - ${text}`);
          }

          const data = await resp.json().catch(() => null);
          results.push(data);

          if (data?.status === 'S') {
            successCount++;
            logger.debug('SMS sent to', { phoneNumber, response: data });
          } else {
            failureCount++;
            failedNumbers.push(phoneNumber);
            logger.warn('SMS failed for', { phoneNumber, response: data });
          }
        } catch (err) {
          failureCount++;
          failedNumbers.push(phoneNumber);
          logger.error('SMS send error for', { phoneNumber, error: err });
        }
      }

      return {
        successCount,
        failureCount,
        failedNumbers,
        results
      };
    },
    invalidateQueries: [
      queryKeys.dashboard.all(),
      queryKeys.reports.all(),
    ],
    onSuccess: (data) => {
      logger.debug('SMS batch send complete', { summary: data });

      if (data.failureCount === 0) {
        success(t('smsSent', { ns: 'sms' }));
      } else if (data.successCount > 0) {
        success(`${t('smsSent', { ns: 'sms' })} (${data.successCount} sent, ${data.failureCount} failed)`);
      } else {
        showError(`Failed to send to all numbers: ${data.failedNumbers.join(', ')}`);
        return;
      }

      // Clear all form fields after send attempt
      setFormData({
        recipientNumber: '',
        recipientFile: null,
        uploadedContacts: [],
        textMessage: '',
        smsType: 'promotional',
        senderId: '',
        encoding: 'Default',
        audience: 'Quick Number List'
      });
      setFormErrors({});
    },
    onError: (err) => {
      logger.error('Send SMS failed', { error: err });
      showError(err.message || t('smsFailed', { ns: 'sms' }));
    },
  });

  const handleSendSMS = async () => {
    const errors = {};

    // Validate all required fields
    if (!formData.textMessage) {
      errors.textMessage = t('enterMessage', { ns: 'sms' });
    }
    if (!formData.senderId) {
      errors.senderId = t('selectSenderId', { ns: 'sms' });
    }
    if (!formData.smsType) {
      errors.smsType = t('fillAllFields', { ns: 'sms' });
    }
    if (!formData.audience) {
      errors.audience = t('fillAllFields', { ns: 'sms' });
    }
    if (!formData.encoding) {
      errors.encoding = t('fillAllFields', { ns: 'sms' });
    }

    // Validate recipient based on audience
    if (formData.audience === 'Quick Number List') {
      if (!formData.recipientNumber) {
        errors.recipientNumber = t('provideRecipientNumbers', { ns: 'sms' });
      }
    } else if (formData.audience === 'Upload File of Numbers') {
      if (formData.uploadedContacts.length === 0) {
        errors.recipientFile = t('uploadFileWithContacts', { ns: 'sms' });
      }
    }

    if (Object.keys(errors).length > 0) {
      setFormErrors(errors);
      showError(t('fillAllFields', { ns: 'sms' }));
      return;
    }

    setFormErrors({});

    let phone = '';

    if (formData.audience === 'Quick Number List') {
      phone = formData.recipientNumber
        .replace(/[\s,;]+/g, ',')
        .split(',')
        .filter(Boolean)
        .map(num => cleanNumberForBackend(num))
        .join(',');
    } else if (formData.audience === 'Upload File of Numbers') {
      phone = formData.uploadedContacts.map(c => c.number).join(',');
    }

    const smsTypeMap = { promotional: 'P', transactional: 'T', otp: 'O' };
    const encodingMap = { Default: 'T', ASCII: 'U', Octets: '8', Latin1: 'L', OctetUnspecified: 'O' };

    const params = {
      api_id: 'Test94687654',
      api_password: 'DFmCBlGPyZaCbPLw',
      sms_type: smsTypeMap[formData.smsType] || 'P',
      encoding: encodingMap[formData.encoding] || 'T',
      sender_id: formData.senderId,
      phonenumber: phone,
      textmessage: formData.textMessage,
      dltEntityId: '45350435',
      dltEntityTemplateId: '23443456',
      ValidityPeriodInSeconds: '1800',
      uid: '2erx4r44',
      callback_url: 'www.ismartghana.com',
      isScheduled: 'false'
    };

    sendSMSMutation.mutate(params);
  };

  return (
    <div>
      <div className="sms-card" style={{ maxWidth: '800px', margin: '0 auto' }}>
        <div className="card-head">
          <h3>{t('sendSMS', { ns: 'sms' })}</h3>
          <p style={{ margin: '4px 0 0 0', color: 'var(--text-muted)', fontSize: '14px' }}>
            Send SMS messages to individual contacts or bulk upload
          </p>
        </div>

        <div style={{ padding: '16px 0' }}>
          <form onSubmit={(e) => { e.preventDefault(); handleSendSMS(); }}>
            {/* Configuration Section */}
            <div style={{
              padding: '16px',
              backgroundColor: 'var(--bg-secondary)',
              borderRadius: '8px',
              marginBottom: '20px',
              border: '1px solid var(--border-primary)'
            }}>
              <h4 style={{ margin: '0 0 16px 0', fontSize: '14px', fontWeight: '600', color: 'var(--text-primary)' }}>
                Configuration
              </h4>

              {/* Top row: SMS Type, Audience, Encoding */}
              <div className="sms-form-row" data-tour="sms-type-audience-encoding" style={{ gap: '12px', marginBottom: '16px' }}>
                <div className="sms-form-field" style={{ flex: 1 }}>
                  <label style={{ display: 'flex', alignItems: 'center', gap: '4px', marginBottom: '8px' }}>
                    <span>{t('smsType', { ns: 'sms' })}</span>
                  </label>
                  <select
                    name="smsType"
                    value={formData.smsType}
                    onChange={handleChange}
                    className="filter"
                    required
                    style={{ borderColor: formErrors.smsType ? 'var(--error)' : '', borderWidth: formErrors.smsType ? '2px' : '' }}
                  >
                    <option value="promotional">{t('promotional', { ns: 'sms' })} - {t('promotionalDesc', { ns: 'sms' })}</option>
                    <option value="transactional">{t('transactional', { ns: 'sms' })} - {t('transactionalDesc', { ns: 'sms' })}</option>
                    <option value="otp">{t('otp', { ns: 'sms' })} - {t('otpDesc', { ns: 'sms' })}</option>
                  </select>
                  {formErrors.smsType && <small style={{ color: 'var(--error)', display: 'block', marginTop: '4px' }}>{formErrors.smsType}</small>}
                </div>

                <div className="sms-form-field" style={{ flex: 1 }}>
                  <label style={{ display: 'flex', alignItems: 'center', gap: '4px', marginBottom: '8px' }}>
                    <span>{t('audience', { ns: 'sms' })}</span>
                  </label>
                  <select
                    name="audience"
                    value={formData.audience}
                    onChange={handleChange}
                    className="filter"
                    required
                    style={{ borderColor: formErrors.audience ? 'var(--error)' : '', borderWidth: formErrors.audience ? '2px' : '' }}
                  >
                    <option value="Quick Number List">{t('quickNumberList', { ns: 'sms' })}</option>
                    <option value="Upload File of Numbers">{t('uploadFile', { ns: 'sms' })}</option>
                  </select>
                  {formErrors.audience && <small style={{ color: 'var(--error)', display: 'block', marginTop: '4px' }}>{formErrors.audience}</small>}
                </div>

                <div className="sms-form-field" style={{ flex: 1 }}>
                  <label style={{ display: 'flex', alignItems: 'center', gap: '4px', marginBottom: '8px' }}>
                    <span>{t('encoding', { ns: 'sms' })}</span>
                  </label>
                  <select
                    name="encoding"
                    value={formData.encoding}
                    onChange={handleChange}
                    className="filter"
                    required
                    title={t('encodingDesc', { ns: 'sms' })}
                    style={{ borderColor: formErrors.encoding ? 'var(--error)' : '', borderWidth: formErrors.encoding ? '2px' : '' }}
                  >
                    <option value="Default">{t('default', { ns: 'sms' })}</option>
                    <option value="ASCII">{t('ascii', { ns: 'sms' })}</option>
                    <option value="Octets">{t('octets', { ns: 'sms' })}</option>
                    <option value="Latin1">{t('latin1', { ns: 'sms' })}</option>
                    <option value="OctetUnspecified">{t('octetUnspecified', { ns: 'sms' })}</option>
                  </select>
                  <small style={{ color: 'var(--text-muted)', display: 'block', marginTop: '4px' }}>
                    {formData.encoding === 'Default' && t('defaultEncodingDesc', { ns: 'sms' })}
                    {formData.encoding === 'ASCII' && t('asciiEncodingDesc', { ns: 'sms' })}
                    {formData.encoding === 'Octets' && t('octetsEncodingDesc', { ns: 'sms' })}
                    {formData.encoding === 'Latin1' && t('latin1EncodingDesc', { ns: 'sms' })}
                    {formData.encoding === 'OctetUnspecified' && t('octetUnspecifiedDesc', { ns: 'sms' })}
                  </small>
                  {formErrors.encoding && <small style={{ color: 'var(--error)', display: 'block', marginTop: '4px' }}>{formErrors.encoding}</small>}
                </div>
              </div>

              {/* Sender ID */}
              <div className="sms-form-row" data-tour="sms-sender-id">
                <div className="sms-form-field" style={{ width: '100%' }}>
                  <label style={{ display: 'flex', alignItems: 'center', gap: '4px', marginBottom: '8px' }}>
                    <span>{t('senderId', { ns: 'sms' })}</span>
                  </label>
                  <input
                    type="text"
                    name="senderId"
                    value={formData.senderId}
                    onChange={handleChange}
                    placeholder={t('senderIdPlaceholder', { ns: 'sms' })}
                    className="filter"
                    required
                    maxLength="11"
                    style={{ borderColor: formErrors.senderId ? 'var(--error)' : '', borderWidth: formErrors.senderId ? '2px' : '' }}
                  />
                  <small style={{ color: 'var(--text-muted)', display: 'block', marginTop: '4px' }}>{t('senderIdDesc', { ns: 'sms' })}</small>
                  {formErrors.senderId && <small style={{ color: 'var(--error)', display: 'block', marginTop: '4px' }}>{formErrors.senderId}</small>}
                </div>
              </div>
            </div>

            {/* Recipients Section */}
            <div style={{
              padding: '16px',
              backgroundColor: 'var(--bg-secondary)',
              borderRadius: '8px',
              marginBottom: '20px',
              border: '1px solid var(--border-primary)'
            }}>
              <h4 style={{ margin: '0 0 16px 0', fontSize: '14px', fontWeight: '600', color: 'var(--text-primary)' }}>
                Recipients
              </h4>

              {formData.audience === 'Quick Number List' && (
                <div className="sms-form-field" data-tour="sms-recipients" style={{ marginBottom: '16px' }}>
                  <label style={{ display: 'flex', alignItems: 'center', gap: '4px', marginBottom: '8px' }}>
                    <span>{t('recipientNumber', { ns: 'sms' })}</span>
                  </label>
                  <input
                    type="text"
                    name="recipientNumber"
                    value={formData.recipientNumber}
                    onChange={handleChange}
                    placeholder={t('recipientNumberPlaceholder', { ns: 'sms' })}
                    className="filter"
                    required
                    style={{ borderColor: formErrors.recipientNumber ? 'var(--error)' : '', borderWidth: formErrors.recipientNumber ? '2px' : '' }}
                  />
                  <small style={{ color: 'var(--text-muted)', display: 'block', marginTop: '4px' }}>Separate numbers with commas or semicolons</small>
                  {formErrors.recipientNumber && <small style={{ color: 'var(--error)', display: 'block', marginTop: '4px' }}>{formErrors.recipientNumber}</small>}
                </div>
              )}

              {formData.audience === 'Upload File of Numbers' && (
                <>
                  <div className="sms-form-field" data-tour="sms-recipients">
                    <label style={{ display: 'flex', alignItems: 'center', gap: '4px', marginBottom: '8px' }}>
                      <span>{t('uploadFileLabel', { ns: 'sms' })}</span>
                    </label>
                    <input
                      type="file"
                      name="recipientFile"
                      onChange={handleChange}
                      accept=".csv,.txt"
                      className="filter"
                      required
                      style={{ borderColor: formErrors.recipientFile ? 'var(--error)' : '', borderWidth: formErrors.recipientFile ? '2px' : '' }}
                    />
                    <small style={{ color: 'var(--text-muted)', display: 'block', marginTop: '4px' }}>CSV format: Name, Phone Number (one per row)</small>
                    {formErrors.recipientFile && <small style={{ color: 'var(--error)', display: 'block', marginTop: '4px' }}>{formErrors.recipientFile}</small>}
                  </div>

                  {formData.uploadedContacts && formData.uploadedContacts.length > 0 && (
                    <div className="sms-form-field" style={{ marginTop: '16px' }}>
                      <label style={{ display: 'flex', alignItems: 'center', gap: '4px', marginBottom: '8px' }}>
                        <span>{t('uploadedContactsPreview', { ns: 'sms' })}</span>
                        <span style={{ backgroundColor: 'var(--accent)', color: 'white', padding: '2px 6px', borderRadius: '4px', fontSize: '12px', fontWeight: '600' }}>
                          {formData.uploadedContacts.length}
                        </span>
                      </label>
                      <div style={{
                        overflowX: 'auto',
                        width: '100%',
                        WebkitOverflowScrolling: 'touch',
                        maxHeight: '400px',
                        overflowY: 'auto',
                        border: '1px solid var(--border-primary)',
                        borderRadius: '8px'
                      }}>
                        <table className="invoices-table" style={{ marginBottom: 0 }}>
                          <thead style={{ position: 'sticky', top: 0 }}>
                            <tr>
                              <th style={{ minWidth: '200px' }}>{t('name', { ns: 'sms' })}</th>
                              <th style={{ minWidth: '150px' }}>{t('phoneNumber', { ns: 'sms' })}</th>
                            </tr>
                          </thead>
                          <tbody>
                            {formData.uploadedContacts.map((contact, index) => (
                              <tr key={index}>
                                <td style={{ fontWeight: '600', color: 'var(--text-primary)' }}>{contact.name}</td>
                                <td style={{ color: 'var(--text-muted)' }}>{contact.number}</td>
                              </tr>
                            ))}
                          </tbody>
                        </table>
                      </div>
                      <div style={{
                        marginTop: '12px',
                        color: 'var(--text-muted)',
                        fontSize: '14px',
                        textAlign: 'center'
                      }}>
                        {t('contactsWillReceiveSMS', { ns: 'sms', count: formData.uploadedContacts.length })}
                      </div>
                    </div>
                  )}
                </>
              )}
            </div>

            {/* Message Section */}
            <div style={{
              padding: '16px',
              backgroundColor: 'var(--bg-secondary)',
              borderRadius: '8px',
              marginBottom: '20px',
              border: '1px solid var(--border-primary)'
            }}>
              <h4 style={{ margin: '0 0 16px 0', fontSize: '14px', fontWeight: '600', color: 'var(--text-primary)' }}>
                Message Content
              </h4>

              {/* Message body */}
              <div className="sms-form-field" data-tour="sms-message">
                <label style={{ display: 'flex', alignItems: 'center', gap: '4px', marginBottom: '8px' }}>
                  <span>{t('message', { ns: 'sms' })}</span>
                </label>
                <textarea
                  name="textMessage"
                  value={formData.textMessage}
                  onChange={handleMessageChange}
                  rows={6}
                  className="filter"
                  placeholder={t('messagePlaceholder', { ns: 'sms' })}
                  required
                  style={{ borderColor: formErrors.textMessage ? 'var(--error)' : '', borderWidth: formErrors.textMessage ? '2px' : '', resize: 'vertical' }}
                />
                {formErrors.textMessage && <small style={{ color: 'var(--error)', display: 'block', marginTop: '4px' }}>{formErrors.textMessage}</small>}
              </div>

              {/* SMS Counter Display - Improved */}
              <div
                data-tour="sms-calculator"
                style={{
                  display: 'flex',
                  justifyContent: 'space-between',
                  alignItems: 'center',
                  padding: '12px 16px',
                  backgroundColor: 'var(--bg-tertiary)',
                  border: '2px solid var(--border-primary)',
                  borderRadius: '8px',
                  marginTop: '12px',
                  fontSize: '14px'
                }}
              >
                <div style={{ display: 'flex', gap: '20px', flexWrap: 'wrap', alignItems: 'center' }}>
                  <span style={{ color: 'var(--text-primary)', fontWeight: '600', display: 'flex', alignItems: 'center', gap: '4px' }}>
                    <span className="material-symbols-outlined" style={{ fontSize: '18px' }}>analytics</span>
                    {t('smsUnitCalculator', { ns: 'sms' })}
                  </span>
                  <span style={{ color: 'var(--text-muted)', fontSize: '13px' }}>
                    {smsStats.characterCount} {t('characterCount', { ns: 'sms' }).toLowerCase()}
                  </span>
                </div>
                <div style={{
                  display: 'flex',
                  alignItems: 'center',
                  gap: '8px',
                  padding: '4px 12px',
                  backgroundColor: smsStats.smsUnits === 1 ? 'rgba(34, 197, 94, 0.1)' : smsStats.smsUnits === 2 ? 'rgba(0, 72, 149, 0.1)' : 'rgba(239, 68, 68, 0.1)',
                  borderRadius: '6px'
                }}>
                  <span style={{
                    fontSize: '18px',
                    fontWeight: '700',
                    color: smsStats.smsUnits === 1 ? 'var(--success)' : smsStats.smsUnits === 2 ? 'var(--accent)' : 'var(--error)'
                  }}>
                    {smsStats.smsUnits}
                  </span>
                  <span style={{
                    fontSize: '13px',
                    fontWeight: '600',
                    color: smsStats.smsUnits === 1 ? 'var(--success)' : smsStats.smsUnits === 2 ? 'var(--accent)' : 'var(--error)'
                  }}>
                    {smsStats.smsUnits === 1 ? t('unit', { ns: 'sms' }) : t('units', { ns: 'sms' })}
                  </span>
                </div>
              </div>
            </div>

            {/* Submit Button Section */}
            <div style={{ display: 'flex', gap: '12px', justifyContent: 'flex-end', marginTop: '24px' }} data-tour="sms-submit">
              <button
                type="submit"
                disabled={sendSMSMutation.isPending}
                className="btn"
                style={{
                  backgroundColor: sendSMSMutation.isPending ? 'var(--text-muted)' : 'var(--accent)',
                  color: 'white',
                  padding: '12px 32px',
                  borderRadius: '8px',
                  border: 'none',
                  fontWeight: '600',
                  cursor: sendSMSMutation.isPending ? 'not-allowed' : 'pointer',
                  opacity: sendSMSMutation.isPending ? 0.6 : 1,
                  transition: 'all var(--transition-base)',
                  display: 'flex',
                  alignItems: 'center',
                  gap: '8px'
                }}
              >
                <span className="material-symbols-outlined" style={{ fontSize: '20px' }}>
                  {sendSMSMutation.isPending ? 'schedule' : 'send'}
                </span>
                {sendSMSMutation.isPending ? t('sending', { ns: 'sms' }) : t('sendSMS', { ns: 'sms' })}
              </button>
            </div>
          </form>
        </div>
      </div>
    </div>
  );
}

export default SMS;
